// ShareReceiverActivity.kt
package com.example.shareapp

import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.util.Patterns
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import java.io.File

class ShareReceiverActivity : AppCompatActivity() {

    companion object {
        private const val MAX_FILE_SIZE = 10 * 1024 * 1024 // 10MB
        private val ALLOWED_MIME_TYPES = setOf(
            "image/jpeg",
            "image/png",
            "image/gif",
            "image/webp"
        )
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        
        if (!isValidShareIntent(intent)) {
            Toast.makeText(this, "Invalid share request", Toast.LENGTH_SHORT).show()
            finish()
            return
        }

        handleShareIntent(intent)
    }

    private fun isValidShareIntent(intent: Intent?): Boolean {
        if (intent == null) return false
        
        val action = intent.action
        if (action != Intent.ACTION_SEND && action != Intent.ACTION_SEND_MULTIPLE) {
            return false
        }

        val type = intent.type
        if (type.isNullOrEmpty()) return false

        return type.startsWith("text/") || type.startsWith("image/")
    }

    private fun handleShareIntent(intent: Intent) {
        when (intent.action) {
            Intent.ACTION_SEND -> {
                if (intent.type?.startsWith("text/") == true) {
                    handleSharedText(intent)
                } else if (intent.type?.startsWith("image/") == true) {
                    handleSharedImage(intent)
                }
            }
            Intent.ACTION_SEND_MULTIPLE -> {
                if (intent.type?.startsWith("image/") == true) {
                    handleSharedImages(intent)
                }
            }
        }
        finish()
    }

    private fun handleSharedText(intent: Intent) {
        val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
        
        if (sharedText.isNullOrBlank()) {
            Toast.makeText(this, "No text content received", Toast.LENGTH_SHORT).show()
            return
        }

        if (sharedText.length > 10000) {
            Toast.makeText(this, "Text content too large", Toast.LENGTH_SHORT).show()
            return
        }

        if (isValidUrl(sharedText)) {
            processUrl(sharedText)
        } else {
            processText(sharedText)
        }
    }

    private fun handleSharedImage(intent: Intent) {
        val imageUri = intent.getParcelableExtra<Uri>(Intent.EXTRA_STREAM)
        
        if (imageUri == null) {
            Toast.makeText(this, "No image received", Toast.LENGTH_SHORT).show()
            return
        }

        if (!isValidImageUri(imageUri)) {
            Toast.makeText(this, "Invalid or unsafe image", Toast.LENGTH_SHORT).show()
            return
        }

        processImage(imageUri)
    }

    private fun handleSharedImages(intent: Intent) {
        val imageUris = intent.getParcelableArrayListExtra<Uri>(Intent.EXTRA_STREAM)
        
        if (imageUris.isNullOrEmpty()) {
            Toast.makeText(this, "No images received", Toast.LENGTH_SHORT).show()
            return
        }

        if (imageUris.size > 10) {
            Toast.makeText(this, "Too many images (max 10)", Toast.LENGTH_SHORT).show()
            return
        }

        val validUris = imageUris.filter { isValidImageUri(it) }
        
        if (validUris.isEmpty()) {
            Toast.makeText(this, "No valid images found", Toast.LENGTH_SHORT).show()
            return
        }

        processImages(validUris)
    }

    private fun isValidUrl(text: String): Boolean {
        if (text.length > 2048) return false
        
        if (!Patterns.WEB_URL.matcher(text).matches()) {
            return false
        }

        val uri = Uri.parse(text)
        val scheme = uri.scheme?.lowercase()
        
        if (scheme != "http" && scheme != "https") {
            return false
        }

        val host = uri.host
        if (host.isNullOrBlank()) return false
        
        if (host == "localhost" || host == "127.0.0.1" || host == "0.0.0.0") {
            return false
        }

        if (host.matches(Regex("^10\\..*")) || 
            host.matches(Regex("^172\\.(1[6-9]|2[0-9]|3[0-1])\\..*")) ||
            host.matches(Regex("^192\\.168\\..*"))) {
            return false
        }

        return true
    }

    private fun isValidImageUri(uri: Uri): Boolean {
        val scheme = uri.scheme?.lowercase()
        if (scheme != "content") {
            return false
        }

        try {
            val mimeType = contentResolver.getType(uri)
            if (mimeType == null || !ALLOWED_MIME_TYPES.contains(mimeType)) {
                return false
            }

            contentResolver.openInputStream(uri)?.use { inputStream ->
                val fileSize = inputStream.available()
                if (fileSize > MAX_FILE_SIZE) {
                    return false
                }
            } ?: return false

            contentResolver.query(uri, null, null, null, null)?.use { cursor ->
                if (!cursor.moveToFirst()) {
                    return false
                }
            } ?: return false

        } catch (e: SecurityException) {
            return false
        } catch (e: Exception) {
            return false
        }

        return true
    }

    private fun processUrl(url: String) {
        Toast.makeText(this, "Processing URL: ${url.take(50)}...", Toast.LENGTH_LONG).show()
    }

    private fun processText(text: String) {
        Toast.makeText(this, "Processing text: ${text.take(50)}...", Toast.LENGTH_LONG).show()
    }

    private fun processImage(uri: Uri) {
        Toast.makeText(this, "Processing image", Toast.LENGTH_SHORT).show()
    }

    private fun processImages(uris: List<Uri>) {
        Toast.makeText(this, "Processing ${uris.size} images", Toast.LENGTH_SHORT).show()
    }
}